// shadcn
import { Button } from "@/components/ui/button";
import {
  Carousel,
  CarouselContent,
  CarouselItem,
  CarouselNext,
  CarouselPrevious,
} from "@/components/ui/carousel";

// constants
const items = [
  {
    id: 1,
    image: "https://cdn.uiable.com/block/g1.jpg",
    title: "Breathe In",
    description:
      "Better a diamond with a flaw than a pebble without one. Life isn't about finding yourself, it's about creating yourself.",
  },
  {
    id: 2,
    image: "https://cdn.uiable.com/block/g2.jpg",
    title: "Breathe In",
    description:
      "Better a diamond with a flaw than a pebble without one. Life isn't about finding yourself, it's about creating yourself.",
  },
  {
    id: 3,
    image: "https://cdn.uiable.com/block/g3.jpg",
    title: "Breathe In",
    description:
      "Better a diamond with a flaw than a pebble without one. Life isn't about finding yourself, it's about creating yourself.",
  },
  {
    id: 4,
    image: "https://cdn.uiable.com/block/g4.jpg",
    title: "Breathe In",
    description:
      "Better a diamond with a flaw than a pebble without one. Life isn't about finding yourself, it's about creating yourself.",
  },
  {
    id: 5,
    image: "https://cdn.uiable.com/block/g5.jpg",
    title: "Breathe In",
    description:
      "Better a diamond with a flaw than a pebble without one. Life isn't about finding yourself, it's about creating yourself.",
  },
];

//  ------------------------------ | PORTFOLIO 3 | ------------------------------  //

export default function Portfolio3() {
  return (
    <section className="py-20 overflow-hidden">
      <div className="container mx-auto px-4 sm:px-6 lg:px-8">
        <Carousel opts={{ align: "start", loop: true }} className="w-full">
          {/* Header row */}
          <div className="grid grid-cols-12 gap-6 items-end mb-10">
            <div className="col-span-12 md:col-span-8 flex flex-col gap-4">
              <h2 className="text-foreground">
                Great Ideas Start With A Scribble
              </h2>
              <p className="text-muted-foreground max-w-md">
                This is a big one and I consider one of the most important, and
                difficult, things for designer to get right.
              </p>
            </div>
            {/* Navigation arrows aligned right — static to override absolute positioning */}
            <div className="col-span-12 md:col-span-4 flex items-center justify-end gap-3">
              <CarouselPrevious className="static translate-y-0" />
              <CarouselNext className="static translate-y-0" />
            </div>
          </div>

          {/* Carousel content */}
          <CarouselContent>
            {items.map((item) => (
              <CarouselItem
                key={item.id}
                className="pl-4 basis-full sm:basis-1/2 lg:basis-1/3"
              >
                <div className="relative overflow-hidden rounded-2xl h-70 group cursor-pointer">
                  {/* Background image */}
                  <img
                    src={item.image}
                    alt={item.title}
                    className="absolute inset-0 w-full h-full object-cover"
                  />
                  {/* gradient overlay — stronger on hover */}
                  <div className="absolute inset-0 bg-linear-to-t from-mist-400/40 via-transparent to-transparent transition-all duration-500 group-hover:from-mist-400/80 group-hover:via-mist-400/30" />
                  {/* Text content — slides up as button appears */}
                  <div className="absolute bottom-0 left-0 right-0 p-6 flex flex-col gap-2 translate-y-12 group-hover:translate-y-0 transition-transform duration-500 ease-out">
                    <h5 className="text-white font-bold">{item.title}</h5>
                    <p className="text-white/80 text-sm">{item.description}</p>
                    <div className="mt-2 opacity-0 group-hover:opacity-100 transition-opacity duration-100 ease-out">
                      <Button className="hover:opacity-75">
                        View Case Study
                      </Button>
                    </div>
                  </div>
                </div>
              </CarouselItem>
            ))}
          </CarouselContent>
        </Carousel>
      </div>
    </section>
  );
}
